1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_BLOCK_OF_3_PRICE = 60;
4	const CURSE_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	type QuoteStep = { type: "quote"; items: Item[] };
20	type Scenario = { steps: QuoteStep[] };
21	
22	function groupByType(items: Item[]): Map<string, Item[]> {
23	  const groups = new Map<string, Item[]>();
24	  for (const item of items) {
25	    const group = groups.get(item.type) ?? [];
26	    group.push(item);
27	    groups.set(item.type, group);
28	  }
29	  return groups;
30	}
31	
32	function isHighlyEnchanted(item: Item): boolean {
33	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
34	}
35	
36	function calculateItemPremium(item: Item): number {
37	  const itemBase = BASE_PREMIUMS[item.type];
38	  const curseSurcharge = item.cursed ? itemBase * CURSE_SURCHARGE_RATE : 0;
39	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
40	    ? itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE
41	    : 0;
42	  return itemBase + curseSurcharge + highEnchantmentSurcharge;
43	}
44	
45	function calculateGroupPremium(type: string, group: Item[]): number {
46	  if (COMPONENT_TYPES.has(type) && group.length === 3) {
47	    return COMPONENT_BLOCK_OF_3_PRICE;
48	  }
49	  return group.reduce((sum, item) => sum + calculateItemPremium(item), 0);
50	}
51	
52	function calculateBasePremium(items: Item[]): number {
53	  return Array.from(groupByType(items)).reduce(
54	    (total, [type, group]) => total + calculateGroupPremium(type, group),
55	    0,
56	  );
57	}
58	
59	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
60	  const { steps } = scenario as Scenario;
61	  const items = steps[0].items;
62	  const basePremium = calculateBasePremium(items);
63	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
64	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
65	  return { results: [{ premium }] };
66	}
